import { Worker } from "bullmq";
import connection from "../../config/redis.js";
import Note from "../../models/note.model.js";
import Subject from "../../models/subject.model.js";
import { analyzeLectureImage } from "../../services/ai/ai.service.js";
import parseAIResponse from "../../utils/parseAIResponse.js";
import apiError from "../../utils/apiError.js";
const downloadImageAsBuffer = async (url) => {
    const response = await fetch(url);
    if (!response.ok) {
        throw new apiError(500, "Failed to fetch image");
    }
    const arrayBuffer = await response.arrayBuffer();
    return Buffer.from(arrayBuffer);
};
export const noteWorker = new Worker("note-processing", async (job) => {
    const { noteId, imageUrl } = job.data;
    const note = await Note.findById(noteId);
    if (!note) {
        throw new apiError(404, "Note not found");
    }
    const existingSubjects = await Subject.find({ userId: note.userId }).select("title").lean();
    const subjectsTitles = existingSubjects.map((s) => s.title);
    note.status = "processing";
    note.processingStartedAt = new Date();
    await note?.save();
    try {
        const imageBuffer = await downloadImageAsBuffer(imageUrl);
        const aiRaw = await analyzeLectureImage(imageBuffer, note.mimeType, subjectsTitles);
        const aiData = parseAIResponse(aiRaw);
        const normalizedSubject = aiData.subject.trim().toLowerCase();
        if (aiData.title === "N/A" ||
            aiData.subject === "N/A" ||
            aiData.topic === "" ||
            aiData.subject === "" ||
            !aiData.topic ||
            !aiData.subject) {
            note.status = "failed";
            note.errorMessage = "No lecture notes detected in image";
            await note.save();
            return;
        }
        if (aiData.title === "Untitled" || aiData.subject === "") {
            note.status = "failed";
            note.errorMessage = "No lecture notes detected in image";
            await note.save();
            return;
        }
        let subject = await Subject.findOne({
            userId: note.userId,
            title: {
                $regex: new RegExp(`^${normalizedSubject}$`, "i"),
            },
        });
        if (!subject) {
            subject = await Subject.create({
                userId: note.userId,
                title: aiData.subject,
                isAutoGenerated: true,
            });
        }
        note.subjectId = subject._id;
        note.title = aiData.topic;
        note.detectedSubject = aiData.subject;
        note.aiContent = aiData.notes;
        note.status = "completed";
        note.processingCompletedAt = new Date();
        await note.save();
    }
    catch (error) {
        if (error.status === 429) {
            note.errorMessage =
                "AI limit reached! (Sorry i am student so I am using free API)";
        }
        else {
            note.errorMessage =
                error instanceof Error ? error.message : "Unknown Error";
        }
        note.status = "failed";
        await note.save();
        throw error;
    }
}, { connection });
